async function runSearch(keyword,page,shouldScrollToResults){elements.searchResults.hidden=!1;elements.searchResults.innerHTML='<div class="ae-browser__section-heading">Search Results</div>';elements.searchResults.insertAdjacentHTML("beforeend",buildEmptyMarkup(config.strings.loading));try{var data=await request(config.actions.search,{keyword:keyword,page:page||1});setDisclaimer(data.disclaimer||"");state.searchKeyword=data.keyword||keyword;state.searchPage=Number(data.page||page||1);renderSearchResults(data);if(shouldScrollToResults){scrollToSearchResults()}}catch(error){renderError(elements.searchResults,error.message,"Search Results");if(shouldScrollToResults){scrollToSearchResults()}}}
